18→export default function OverviewPage() {
19→  const { data: session } = useSession();
20→  const { repos, isLoading } = useRepos();
21→
22→  const firstName = session?.user?.name?.split(" ")[0] || "there";
23→  const totalCheckpoints = repos?.reduce((sum, r) => sum + r.checkpoint_count, 0) ?? 0;
24→  const reposWithCheckpoints = repos?.filter((r) => r.checkpoint_count > 0).length ?? 0;
25→
26→  // Build heatmap data from repo updated_at as a proxy (real data would come from checkpoints)
27→  const heatmapData: Record<string, number> = {};
28→  if (repos) {
29→    for (const repo of repos) {
30→      if (repo.checkpoint_count > 0) {
31→        const date = repo.updated_at.split("T")[0];
32→        heatmapData[date] = (heatmapData[date] || 0) + repo.checkpoint_count;
33→      }
34→    }
35→  }
36→
37→  if (isLoading) {
38→    return (
39→      <div className="space-y-6">
40→        <Skeleton className="h-8 w-64" />
41→        <div className="grid grid-cols-4 gap-4">
42→          <Skeleton className="h-24" />
43→          <Skeleton className="h-24" />
44→          <Skeleton className="h-24" />
45→          <Skeleton className="h-24" />
46→        </div>
47→        <Skeleton className="h-40" />
48→      </div>
49→    );
50→  }
51→
52→  return (
53→    <div className="space-y-6">
54→      <h2 className="text-lg font-semibold text-foreground">
55→        {getGreeting()}, {firstName}
56→      </h2>
57→
58→      <div className="grid grid-cols-4 gap-4">
59→        <StatCard label="Checkpoints" value={totalCheckpoints} />
60→        <StatCard label="Repositories" value={reposWithCheckpoints} />
61→        <StatCard
62→          label="Total Repos"
63→          value={repos?.length ?? 0}
64→        />
65→        <StatCard
66→          label="Streak"
67→          value={Object.keys(heatmapData).length}
68→          unit="days"
69→        />
70→      </div>
71→
72→      <Heatmap data={heatmapData} />
73→
74→      {reposWithCheckpoints > 0 && (
75→        <div className="space-y-3">
76→          <h3 className="text-sm font-medium text-muted">Recent Activity</h3>
77→          <RecentCommitsTable />
78→        </div>
79→      )}
80→
81→      {totalCheckpoints === 0 && (
82→        <EmptyState
83→          title="No checkpoints yet"
84→          description="Run partio commit in a repo to capture your first checkpoint."
85→        />
86→      )}
87→    </div>
88→  );
89→}
