 1→import { Octokit } from "@octokit/rest";
 2→import { listCheckpoints } from "@/lib/github/checkpoints";
 3→import { listCommits } from "@/lib/github/commits";
 4→import { getSessionData } from "@/lib/github/session";
 5→import type { RepoLatestCheckpoint } from "@/types/repository";
 6→
 7→export async function getRecentCheckpointsForRepos(
 8→  octokit: Octokit,
 9→  repos: { owner: string; name: string }[]
10→): Promise<RepoLatestCheckpoint[]> {
11→  const results = await Promise.allSettled(
12→    repos.map(async (repo) => {
13→      const checkpoints = await listCheckpoints(
14→        octokit,
15→        repo.owner,
16→        repo.name
17→      );
18→      if (checkpoints.length === 0) return null;
19→
20→      const latest = checkpoints[0];
21→
22→      // Try to fetch the commit for context (message, author)
23→      let commit = null;
24→      try {
25→        const commits = await listCommits(octokit, repo.owner, repo.name, {
26→          sha: latest.commit_hash,
27→          per_page: 1,
28→        });
29→        if (commits.length > 0) commit = commits[0];
30→      } catch {
31→        // Commit may no longer exist — that's fine
32→      }
33→
34→      // Extract the first human message from the session transcript as a summary
35→      let summary: string | null = null;
36→      try {
37→        const messages = await getSessionData(
38→          octokit,
39→          repo.owner,
40→          repo.name,
41→          latest.id
42→        );
43→        const firstHuman = messages.find(
44→          (m) => m.role === "human" || m.role === "user"
45→        );
46→        if (firstHuman) {
47→          const text = firstHuman.content.split("\n")[0].trim();
48→          summary = text.length > 100 ? text.slice(0, 100) + "…" : text;
49→        }
50→      } catch {
51→        // Session data may not be available — that's fine
52→      }
53→
54→      return {
55→        owner: repo.owner,
56→        repo: repo.name,
57→        checkpoint: {
58→          id: latest.id,
59→          commit_hash: latest.commit_hash,
60→          branch: latest.branch,
61→          created_at: latest.created_at,
62→          agent: latest.agent,
63→          agent_percent: latest.agent_percent,
64→        },
65→        commit,
66→        summary,
67→      } satisfies RepoLatestCheckpoint;
68→    })
69→  );
70→
71→  return results
72→    .filter(
73→      (r): r is PromiseFulfilledResult<RepoLatestCheckpoint> =>
74→        r.status === "fulfilled" && r.value !== null
75→    )
76→    .map((r) => r.value)
77→    .sort(
78→      (a, b) =>
79→        new Date(b.checkpoint.created_at).getTime() -
80→        new Date(a.checkpoint.created_at).getTime()
81→    );
82→}
