import { Octokit } from "@octokit/rest";
import { listCheckpoints } from "@/lib/github/checkpoints";
import { listCommits } from "@/lib/github/commits";
import { getSessionData } from "@/lib/github/session";
import type { RepoLatestCheckpoint } from "@/types/repository";

export async function getRecentCheckpointsForRepos(
  octokit: Octokit,
  repos: { owner: string; name: string }[]
): Promise<RepoLatestCheckpoint[]> {
  const results = await Promise.allSettled(
    repos.map(async (repo) => {
      const checkpoints = await listCheckpoints(
        octokit,
        repo.owner,
        repo.name
      );
      if (checkpoints.length === 0) return null;

      const latest = checkpoints[0];

      // Try to fetch the commit for context (message, author)
      let commit = null;
      try {
        const commits = await listCommits(octokit, repo.owner, repo.name, {
          sha: latest.commit_hash,
          per_page: 1,
        });
        if (commits.length > 0) commit = commits[0];
      } catch {
        // Commit may no longer exist — that's fine
      }

      // Extract the first human message from the session transcript as a summary
      let summary: string | null = null;
      try {
        const messages = await getSessionData(
          octokit,
          repo.owner,
          repo.name,
          latest.id
        );
        const firstHuman = messages.find(
          (m) => m.role === "human" || m.role === "user"
        );
        if (firstHuman) {
          const text = firstHuman.content.split("\n")[0].trim();
          summary = text.length > 100 ? text.slice(0, 100) + "…" : text;
        }
      } catch {
        // Session data may not be available — that's fine
      }

      return {
        owner: repo.owner,
        repo: repo.name,
        checkpoint: {
          id: latest.id,
          commit_hash: latest.commit_hash,
          branch: latest.branch,
          created_at: latest.created_at,
          agent: latest.agent,
          agent_percent: latest.agent_percent,
        },
        commit,
        summary,
      } satisfies RepoLatestCheckpoint;
    })
  );

  return results
    .filter(
      (r): r is PromiseFulfilledResult<RepoLatestCheckpoint> =>
        r.status === "fulfilled" && r.value !== null
    )
    .map((r) => r.value)
    .sort(
      (a, b) =>
        new Date(b.checkpoint.created_at).getTime() -
        new Date(a.checkpoint.created_at).getTime()
    );
}

