          <tr className="border-b border-border bg-surface">
            {columns.map((col) => (
              <th
                key={col.key}
                className={cn(
                  "px-4 py-3 text-left text-xs font-medium uppercase tracking-wider text-muted",
                  col.className
                )}
              >
                {col.header}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {data.map((item, idx) => {
            const title = rowTitle?.(item);
            return (
              <tr
                key={idx}
                onClick={() => onRowClick?.(item)}
                className={cn(
                  "border-b border-border bg-surface/50 transition-colors last:border-b-0",
                  onRowClick && "cursor-pointer hover:bg-surface-light",
                  title && "group/tip",
                  rowClassName?.(item)
                )}
              >
                {columns.map((col, ci) => (
                  <td
                    key={col.key}
                    className={cn(
                      "px-4 py-3",
                      col.className,
                      ci === 0 && title && "relative"
                    )}
                  >
                    {col.render(item)}
                    {ci === 0 && title && (
                      <div className="pointer-events-none invisible absolute bottom-full left-4 z-10 mb-2 whitespace-nowrap rounded bg-foreground px-2.5 py-1.5 text-xs text-background shadow-lg group-hover/tip:visible">
                        {title}
                      </div>
                    )}
                  </td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

