  const { items, isLoading } = useRecentCheckpoints();

  if (isLoading) {
    return <Skeleton className="h-48" />;
  }

  if (!items || items.length === 0) {
    return null;
  }

  return (
    <DataTable<RepoLatestCheckpoint>
      data={items}
      onRowClick={(item) =>
        router.push(
          `/${item.owner}/${item.repo}/checkpoints/${item.checkpoint.id}`
        )
      }
      rowClassName={(item) => (item.commit === null ? "opacity-40" : "")}
      rowTitle={(item) =>
        item.commit === null
          ? "This commit no longer exists \u2014 it was likely rebased, squashed, or force-pushed away"
          : undefined
      }
      columns={[
        {
          key: "repo",
          header: "Repository",
          render: (item) => (
            <span className="text-sm font-medium text-foreground">
              {item.owner}/{item.repo}
            </span>
          ),
          className: "w-48",
        },
