          key: "message",
          header: "Commit",
          render: (item) => {
            const text =
              item.summary || item.commit?.message.split("\n")[0] || null;
            return (
              <div className="flex items-center gap-2">
                {item.commit === null && (
                  <span className="shrink-0">&#x26A0;&#xFE0F;</span>
                )}
