                  <span className="truncate text-sm text-foreground">
                    {text}
                  </span>
                )}
                <span className="shrink-0 font-mono text-xs text-muted">
                  {item.checkpoint.commit_hash.slice(0, 7)}
                </span>
              </div>
            );
          },
        },
        {
          key: "agent",
          header: "Agent",
          render: (item) => (
            <div className="flex items-center gap-2">
